import React, { useEffect, useState, useRef } from 'react';
import './Home.css';

// ─────────────────────────────────────────────────────────────────────────────
// 📸 IMAGE IMPORTS
// Put all your images inside:  src/assets/images/
// Then replace the placeholder filenames below with your actual file names.
// ─────────────────────────────────────────────────────────────────────────────

// HERO SLIDESHOW — background image shown behind each slide (landscape ~1400×700px)
import slideImg1 from './assets/images/slide-1.jpg';   // Slide 1 · "5+1 Meals" promo
import slideImg2 from './assets/images/slide-2.jpg';   // Slide 2 · Handcrafted chicken close-up
import slideImg3 from './assets/images/slide-3.jpg';   // Slide 3 · Crispy wings action shot

// HERO RIGHT PANEL — large portrait image on the right side of the hero (~600×700px)
import heroFeatureImg from './assets/images/hero-feature.jpg';

// STORY SECTION — photo beside the brand origin text (~700×450px)
import storyImg from './assets/images/story.jpg';

// MENU CATEGORY CARDS — one photo per card (square/portrait ~600×600px)
import menuKoreanFeast from './assets/images/menu-korean-feast.jpg';
import menuSeafoodRack from './assets/images/menu-seafood-rack.jpg';
import menuToShare     from './assets/images/menu-to-share.jpg';
import menuRiceBowls   from './assets/images/menu-rice-bowls.jpg';

// FEATURED DISH CARDS — one photo per dish (~500×400px)
import dishDragonWing    from './assets/images/dish-dragon-wing.jpg';
import dishBBQRibs       from './assets/images/dish-bbq-ribs.jpg';
import dishInfernoBurger from './assets/images/dish-inferno-burger.jpg';
import dishGarlicPasta   from './assets/images/dish-garlic-pasta.jpg';

// GALLERY — 6 food / ambiance photos (any size, auto-cropped by the grid)
// Note: gallery-1 and gallery-4 occupy two rows (tall slots) — use portrait photos there
import gallery1 from './assets/images/gallery-1.jpg';
import gallery2 from './assets/images/gallery-2.jpg';
import gallery3 from './assets/images/gallery-3.jpg';
import gallery4 from './assets/images/gallery-4.jpg';
import gallery5 from './assets/images/gallery-5.jpg';
import gallery6 from './assets/images/gallery-6.jpg';

// ─── DATA ─────────────────────────────────────────────────────────────────────

const SLIDES = [
  {
    id: 1,
    tag: 'Limited Time Offer',
    headline: ['5 + 1', 'MEALS'],
    sub: 'Save as much as 20% — the more you share, the more you save.',
    savings: 'Save as much as ₱298',
    bg: 'linear-gradient(120deg, #c8102e 0%, #8b0000 100%)',
    img: slideImg1,
  },
  {
    id: 2,
    tag: 'Signature Series',
    headline: ['HANDCRAFTED', 'FLAVOR'],
    sub: 'Every piece hand-brushed twice with our legendary Korean sauce.',
    savings: 'Now available for delivery',
    bg: 'linear-gradient(120deg, #0d0d0d 0%, #1a0005 100%)',
    img: slideImg2,
  },
  {
    id: 3,
    tag: 'Fan Favorite',
    headline: ['BOLD.', 'CRISPY.'],
    sub: 'Double-fried perfection — light, crunchy, impossibly good.',
    savings: 'Order online today',
    bg: 'linear-gradient(120deg, #6b0010 0%, #c8102e 100%)',
    img: slideImg3,
  },
];

const STATS = [
  { value: '150+', label: 'Menu Items' },
  { value: '25K+', label: 'Happy Guests' },
  { value: '12',   label: 'Years of Flavor' },
